// For each active, booking-enabled client: text tomorrow's customers an
// iMessage reminder via BlueBubbles, and Telegram the owner a heads-up count.
// All local — no external services.
const http = this.helpers.httpRequest;
const env = (k, d='') => ($env[k] ?? d);
const CORE = env('CORE_API_URL', 'http://127.0.0.1:8003').replace(/\/$/, '');
const BB = env('BLUEBUBBLES_URL', '').replace(/\/$/, '');
const BB_PW = env('BLUEBUBBLES_PASSWORD', '');
const TG_TOKEN = env('TELEGRAM_BOT_TOKEN', '');
const KEY = env('LAZUSAI_CORE_KEY', '');
const hdr = { 'X-LazusAI-Key': KEY, 'Content-Type': 'application/json' };

const tzMin = parseInt(env('TZ_OFFSET_MIN', '0'), 10) || 0;
const tomorrow = new Date(Date.now() + tzMin * 60000 + 86400000).toISOString().slice(0, 10);

function fmtTime(hhmm){ const [h,m]=hhmm.split(':').map(Number); const ap=h<12?'AM':'PM'; return `${(h%12)||12}:${String(m).padStart(2,'0')} ${ap}`; }

const out = [];
for (const item of $input.all()) {
  const c = item.json;
  if (c.active === false) continue;
  const clientId = c.client_id;
  let cfg;
  try { cfg = await http({ method: 'GET', url: `${CORE}/clients/${clientId}/config`, headers: hdr, json: true }); } catch (e) { continue; }
  if (!cfg.booking_enabled) continue;

  let res;
  try { res = await http({ method: 'GET', url: `${CORE}/clients/${clientId}/bookings?date=${tomorrow}`, headers: hdr, json: true }); } catch (e) { continue; }
  const due = (res.bookings || []).filter(b => ['pending','confirmed'].includes(b.status) && !b.reminded_at);
  let sent = 0;
  for (const b of due) {
    if (!b.customer_phone || !BB) continue;
    const chatGuid = b.customer_phone.startsWith('iMessage;') ? b.customer_phone : `iMessage;-;${b.customer_phone}`;
    const msg = `Reminder from ${cfg.business_name}: you're booked for ${b.service} tomorrow at ${fmtTime(b.start)}${b.staff ? ` with ${b.staff}` : ''}. Reply here to change it.`;
    try {
      await http({ method: 'POST', url: `${BB}/api/v1/message/text`, qs: { password: BB_PW },
        body: { chatGuid, tempGuid: 'lazusai-rem-' + Date.now() + '-' + sent, message: msg, method: 'private-api' }, json: true });
      // Mark so we never double-remind.
      await http({ method: 'PATCH', url: `${CORE}/clients/${clientId}/bookings/${b.id}`, headers: hdr, body: { reminded_at: new Date().toISOString() }, json: true }).catch(() => {});
      sent++;
    } catch (e) { /* skip this one */ }
  }

  const chatId = (cfg.owner_telegram || '').replace(/^@/, '');
  if (TG_TOKEN && chatId && due.length) {
    await http({ method: 'POST', url: `https://api.telegram.org/bot${TG_TOKEN}/sendMessage`,
      body: { chat_id: chatId, text: `📅 ${cfg.business_name}: ${due.length} appointment(s) tomorrow. Reminders sent to ${sent} customer(s).` }, json: true }).catch(() => {});
  }
  out.push({ json: { client_id: clientId, tomorrow, due: due.length, reminders_sent: sent } });
}
return out.length ? out : [{ json: { ran: true, reminders_sent: 0 } }];
